Code Good:
$errorMiddleware = $app->addErrorMiddleware(true, true, true);
$errorMiddleware->setDefaultErrorHandler(function (
    ServerRequestInterface $request,
    Throwable $exception,
    bool $displayErrorDetails
) use ($app) {
    $payload = ['error' => $exception->getMessage()];
    if ($displayErrorDetails) {
        $payload['trace'] = $exception->getTraceAsString();
    }
    $response = $app->getResponseFactory()->createResponse();
    $response->getBody()->write(json_encode($payload));
    $statusCode = ($exception instanceof HttpException) ? $exception->getCode() : 500;
    return $response->withStatus($statusCode)->withHeader('Content-Type', 'application/json');
});

class PostController {
    public function index(Request $request, Response $response): Response {
        $posts = $this->repository->findAll();
        $payload = json_encode(['data' => $posts, 'count' => count($posts)]);
        $response->getBody()->write($payload);
        return $response
            ->withHeader('Content-Type', 'application/json')
            ->withStatus(200);
    }
    public function show(Request $request, Response $response, array $args): Response {
        $post = $this->repository->find((int) $args['id']);
        if (!$post) {
            throw new HttpNotFoundException($request, 'Post not found');
        }
        $response->getBody()->write(json_encode(['data' => $post]));
        return $response->withHeader('Content-Type', 'application/json');
    }
}

class PostApiTest extends TestCase {
    private App $app;
    protected function setUp(): void {
        $this->app = $this->createApp(); // Factory method
    }
    public function testListPosts(): void {
        $request = $this->createRequest('GET', '/api/v1/posts');
        $response = $this->app->handle($request);
        $this->assertEquals(200, $response->getStatusCode());
        $body = json_decode((string) $response->getBody(), true);
        $this->assertArrayHasKey('data', $body);
    }
    private function createRequest(string $method, string $uri): Request {
        return (new ServerRequestFactory())->createServerRequest($method, $uri);
    }
}

